impl tdbin::ColumnGroup for BenchSelectionChanged {
    const COLUMNS: u16 = 8;

    fn write_group<'v, I>(
        items: I,
        count: usize,
        w: &mut tdbin::Writer,
        at: usize,
    ) -> Result<(), tdbin::EncodeError>
    where
        I: Iterator<Item = &'v Self> + Clone,
        Self: 'v,
    {
        w.var_column(
            at,
            1,
            0,
            1,
            count,
            items.clone().map(|row| row.document_id.as_bytes()),
        )?;
        let node_ids_counts = items
            .clone()
            .map(|row| u32::try_from(row.node_ids.len()))
            .collect::<Result<Vec<_>, _>>()
            .map_err(|_| tdbin::EncodeError::LimitExceeded)?;
        w.len_column(at, 1, 2, &node_ids_counts)?;
        let node_ids_total = items
            .clone()
            .map(|row| row.node_ids.len())
            .try_fold(0_usize, usize::checked_add)
            .ok_or(tdbin::EncodeError::LimitExceeded)?;
        w.var_column(
            at,
            1,
            3,
            4,
            node_ids_total,
            items
                .clone()
                .flat_map(|row| row.node_ids.iter())
                .map(String::as_bytes),
        )?;
        let edge_ids_counts = items
            .clone()
            .map(|row| u32::try_from(row.edge_ids.len()))
            .collect::<Result<Vec<_>, _>>()
            .map_err(|_| tdbin::EncodeError::LimitExceeded)?;
        w.len_column(at, 1, 5, &edge_ids_counts)?;
        let edge_ids_total = items
            .clone()
            .map(|row| row.edge_ids.len())
            .try_fold(0_usize, usize::checked_add)
            .ok_or(tdbin::EncodeError::LimitExceeded)?;
        w.var_column(
            at,
            1,
            6,
            7,
            edge_ids_total,
            items
                .clone()
                .flat_map(|row| row.edge_ids.iter())
                .map(String::as_bytes),
        )?;
        Ok(())
    }

    fn read_group(
        r: &tdbin::Reader<'_>,
        at: usize,
        count: usize,
    ) -> Result<Vec<Self>, tdbin::DecodeError> {
        let mut document_id = r.var_column(at, 0, 1, count)?.into_strings()?.into_iter();
        let node_ids_counts = r.len_column(at, 2, count)?;
        let node_ids_total = tdbin::column_total(&node_ids_counts)?;
        let mut node_ids = r
            .var_column(at, 3, 4, node_ids_total)?
            .into_strings()?
            .into_iter();
        let edge_ids_counts = r.len_column(at, 5, count)?;
        let edge_ids_total = tdbin::column_total(&edge_ids_counts)?;
        let mut edge_ids = r
            .var_column(at, 6, 7, edge_ids_total)?
            .into_strings()?
            .into_iter();
        let mut rows = Vec::with_capacity(count);
        for i in 0..count {
            let node_ids_take = usize::try_from(node_ids_counts.get(i).copied().unwrap_or(0))
                .map_err(|_| tdbin::DecodeError::LimitExceeded)?;
            let edge_ids_take = usize::try_from(edge_ids_counts.get(i).copied().unwrap_or(0))
                .map_err(|_| tdbin::DecodeError::LimitExceeded)?;
            rows.push(Self {
                document_id: document_id
                    .next()
                    .ok_or(tdbin::DecodeError::MalformedColumn)?,
                node_ids: (0..node_ids_take)
                    .map(|_| node_ids.next().ok_or(tdbin::DecodeError::MalformedColumn))
                    .collect::<Result<Vec<_>, _>>()?,
                edge_ids: (0..edge_ids_take)
                    .map(|_| edge_ids.next().ok_or(tdbin::DecodeError::MalformedColumn))
                    .collect::<Result<Vec<_>, _>>()?,
            });
        }
        Ok(rows)
    }
}

