impl tdbin::Struct for BenchMetricBatch {
    const DATA_WORDS: u16 = 1;
    const PTR_WORDS: u16 = 7;
    const LAYOUT_HASH: u64 = 0x24e1_dc71_6e37_989f;

    fn write_struct(&self, w: &mut tdbin::Writer, at: usize) -> Result<(), tdbin::EncodeError> {
        w.string(at, Self::DATA_WORDS, 0, Some(&self.batch_id))?;
        w.scalar(at, 0, tdbin::scalar::i64_bits(self.started_at_epoch_ms))?;
        w.i64_block_list(at, Self::DATA_WORDS, 1, Some(&self.sample_ids))?;
        w.bool_list(at, Self::DATA_WORDS, 2, Some(&self.valid))?;
        w.f64_list(at, Self::DATA_WORDS, 3, Some(&self.latency_ms))?;
        w.bytes_var_list(at, Self::DATA_WORDS, 4, 5, Some(&self.payloads))?;
        w.column_list(at, Self::DATA_WORDS, 6, Some(&self.columns))?;
        Ok(())
    }

    fn read_struct(r: &tdbin::Reader<'_>, at: usize) -> Result<Self, tdbin::DecodeError> {
        let batch_id = r.string(at, Self::DATA_WORDS, 0)?.unwrap_or_default();
        let started_at_epoch_ms = tdbin::scalar::i64_from(r.scalar(at, 0)?);
        let sample_ids = r
            .i64_block_list(at, Self::DATA_WORDS, 1)?
            .unwrap_or_default();
        let valid = r.bool_list(at, Self::DATA_WORDS, 2)?.unwrap_or_default();
        let latency_ms = r.f64_list(at, Self::DATA_WORDS, 3)?.unwrap_or_default();
        let payloads = match r.var_list(at, Self::DATA_WORDS, 4, 5)? {
            Some(column) => column.into_byte_vecs()?,
            None => Vec::new(),
        };
        let columns = r
            .column_list::<BenchMetricColumn>(at, Self::DATA_WORDS, 6)?
            .unwrap_or_default();
        Ok(Self {
            batch_id,
            started_at_epoch_ms,
            sample_ids,
            valid,
            latency_ms,
            payloads,
            columns,
        })
    }
}

impl tdbin::Struct for BenchMetricColumn {
    const DATA_WORDS: u16 = 0;
    const PTR_WORDS: u16 = 2;
    const LAYOUT_HASH: u64 = 0x38b8_b754_3c03_df8f;

    fn write_struct(&self, w: &mut tdbin::Writer, at: usize) -> Result<(), tdbin::EncodeError> {
        w.string(at, Self::DATA_WORDS, 0, Some(&self.name))?;
        w.f64_list(at, Self::DATA_WORDS, 1, Some(&self.values))?;
        Ok(())
    }

    fn read_struct(r: &tdbin::Reader<'_>, at: usize) -> Result<Self, tdbin::DecodeError> {
        let name = r.string(at, Self::DATA_WORDS, 0)?.unwrap_or_default();
        let values = r.f64_list(at, Self::DATA_WORDS, 1)?.unwrap_or_default();
        Ok(Self { name, values })
    }
}

impl tdbin::ColumnGroup for BenchMetricColumn {
    const COLUMNS: u16 = 4;

    fn write_group<'v, I>(
        items: I,
        count: usize,
        w: &mut tdbin::Writer,
        at: usize,
    ) -> Result<(), tdbin::EncodeError>
    where
        I: Iterator<Item = &'v Self> + Clone,
        Self: 'v,
    {
        w.var_column(
            at,
            1,
            0,
            1,
            count,
            items.clone().map(|row| row.name.as_bytes()),
        )?;
        let values_counts = items
            .clone()
            .map(|row| u32::try_from(row.values.len()))
            .collect::<Result<Vec<_>, _>>()
            .map_err(|_| tdbin::EncodeError::LimitExceeded)?;
        w.len_column(at, 1, 2, &values_counts)?;
        let values_total = items
            .clone()
            .map(|row| row.values.len())
            .try_fold(0_usize, usize::checked_add)
            .ok_or(tdbin::EncodeError::LimitExceeded)?;
        w.f64_column(
            at,
            1,
            3,
            values_total,
            items.clone().flat_map(|row| row.values.iter()).copied(),
        )?;
        Ok(())
    }

    fn read_group(
        r: &tdbin::Reader<'_>,
        at: usize,
        count: usize,
    ) -> Result<Vec<Self>, tdbin::DecodeError> {
        let mut name = r.var_column(at, 0, 1, count)?.into_strings()?.into_iter();
        let values_counts = r.len_column(at, 2, count)?;
        let values_total = tdbin::column_total(&values_counts)?;
        let mut values = r.f64_column(at, 3, values_total)?.into_iter();
        let mut rows = Vec::with_capacity(count);
        for i in 0..count {
            let values_take = usize::try_from(values_counts.get(i).copied().unwrap_or(0))
                .map_err(|_| tdbin::DecodeError::LimitExceeded)?;
            rows.push(Self {
                name: name.next().ok_or(tdbin::DecodeError::MalformedColumn)?,
                values: (0..values_take)
                    .map(|_| values.next().ok_or(tdbin::DecodeError::MalformedColumn))
                    .collect::<Result<Vec<_>, _>>()?,
            });
        }
        Ok(rows)
    }
}
